PROCEDURE reverseList(lst)
{
  reversed ← []
  i ← LENGTH(lst)
  REPEAT UNTIL(i < 1)
  {
    APPEND(reversed, lst[i])
    i ← i - 1
  }
  RETURN(reversed)
}
DISPLAY(reverseList([1, 2, 3]))

PROCEDURE applyToAll(lst, factor)
{
  i ← 1
  REPEAT UNTIL(i > LENGTH(lst))
  {
    lst[i] ← lst[i] * factor
    i ← i + 1
  }
  RETURN(lst)
}
nums ← [2, 4, 6, 8]
DISPLAY(applyToAll(nums, 3))

