PROCEDURE compress(str)
{
  result ← ""
  i ← 1
  REPEAT UNTIL(i > LENGTH(str))
  {
    IF(str[i] = str[i + 1])
    {
      i ← i + 2
    }
    ELSE
    {
      result ← result + str[i]
      i ← i + 1
    }
  }
  RETURN(result)
}
DISPLAY(compress("aabbc"))

