PROCEDURE addUnique(lst, val)
{
  found ← false
  FOR EACH item IN lst
  {
    IF(item = val)
    {
      found ← true
    }
  }
  IF(NOT found)
  {
    APPEND(lst, val)
  }
  RETURN(lst)
}

