PROCEDURE segmentA(n)
{
  result ← 1
  REPEAT n TIMES
  {
    result ← result * 2
  }
  RETURN(result)
}

PROCEDURE segmentB(n)
{
  IF(n = 0)
  {
    RETURN(1)
  }
  ELSE
  {
    RETURN(2 * segmentB(n - 1))
  }
}

