PROCEDURE buildOdds(n)
{
  odds ← []
  i ← 1
  REPEAT UNTIL(i > n)
  {
    IF(i MOD 2 ≠ 0)
    {
      APPEND(odds, i)
    }
    i ← i + 1
  }
  RETURN(odds)
}
DISPLAY(buildOdds(8))

PROCEDURE flatten(matrix)
{
  result ← []
  FOR EACH row IN matrix
  {
    FOR EACH val IN row
    {
      APPEND(result, val)
    }
  }
  RETURN(result)
}

grid ← [[1, 2], [3, 4], [5, 6]]
DISPLAY(flatten(grid))

PROCEDURE rotateLeft(lst)
{
  IF(LENGTH(lst) = 0)
  {
    RETURN(lst)
  }
  first ← lst[1]
  REMOVE(lst, 1)
  APPEND(lst, first)
  RETURN(lst)
}

DISPLAY(rotateLeft([10, 20, 30, 40]))

PROCEDURE isBalanced(lst)
{
  low ← 0
  high ← LENGTH(lst)
  REPEAT UNTIL(low ≥ high)
  {
    mid ← (low + high + 1) / 2
    IF(lst[mid] = mid)
    {
      RETURN(true)
    }
    ELSE
    {
      IF(lst[mid] < mid)
      {
        low ← mid
      }
      ELSE
      {
        high ← mid - 1
      }
    }
  }
  RETURN(false)
}

PROCEDURE filterPositive(lst)
{
  result ← []
  FOR EACH x IN lst
  {
    IF(x > 0)
    {
      APPEND(result, x)
    }
  }
  RETURN(result)
}

DISPLAY(LENGTH(filterPositive([-3, 5, -1, 0, 8, -2, 7])))

PROCEDURE sumEvens(lst)
{
  total ← 0
  FOR EACH n IN lst
  {
    total ← total + n
  }
  RETURN(total)
}

PROCEDURE sumEvensV2(lst)
{
  total ← 0
  FOR EACH n IN lst
  {
    IF(n MOD 2 = 0)
    {
      total ← total + n
    }
  }
  RETURN(total)
}
